import{_ as l,c as r,o,ag as i}from"./chunks/framework.S-Qvb3wi.js";const h=JSON.parse('{"title":"流通機製：閉環價值循環","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Circulation-Mechanism.md","filePath":"zh-TW/Circulation-Mechanism.md"}'),a={name:"zh-TW/Circulation-Mechanism.md"};function s(n,t,e,d,c,p){return o(),r("div",null,t[0]||(t[0]=[i('<h1 id="流通機製-閉環價值循環" tabindex="-1">流通機製：閉環價值循環 <a class="header-anchor" href="#流通機製-閉環價值循環" aria-label="Permalink to &quot;流通機製：閉環價值循環&quot;">​</a></h1><p>$DGAI 運行於一個閉環經濟系統中，確保價值在用戶、節點運營商及更廣泛的生態系統之間透明流動。該機製由智能合約（如 Bill Contract）治理，並通過 DGrid 節點強制執行，消除中間環節並使激勵機製與網絡健康狀況保持一致。</p><h2 id="核心循環-從支付到獎勵" tabindex="-1">核心循環：從支付到獎勵 <a class="header-anchor" href="#核心循環-從支付到獎勵" aria-label="Permalink to &quot;核心循環：從支付到獎勵&quot;">​</a></h2><p>$DGAI 的流通遵循結構化流程，將用戶對推理的需求與節點貢獻相鏈接：</p><ol><li><strong>用戶支付發起</strong></li></ol><p>當用戶通過用戶客戶端提交推理請求時，流程如下：</p><ul><li>請求被路由至 DGrid 節點，該節點使用以下公式計算任務費用：</li></ul><p><code>成本 = 計算單元 (CU) × 基礎價格 × (1 + 延遲懲罰系數)</code></p><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li><strong>計算單元（CU）</strong>: 用於衡量推理復雜度的標準化指標（與模型大小、輸入令牌數量及執行時間相關）。</li><li><strong>基礎價格</strong>: 每CU固定價格（可通過治理機製調整，初始值為0.05 $DGAI）。</li><li><strong>延遲懲罰系數</strong>: 0–0.3（針對超過目標閾值的延遲進行微調）。</li></ul></div><ul><li>用戶的 $DGAI 通過賬單合約（一個部署在區塊鏈上的智能合約）進行托管，以確保任務完成後支付。</li></ul><ol start="2"><li><strong>節點獎勵分配</strong></li></ol><p>推理完成後（由 Grid Nodes 驗證並存檔到 AI DA），托管的 $DGAI 通過賬單合約進行分配。</p><p>接收方：</p><ul><li><strong>DGrid 節點</strong>：執行推理任務的補償（與 CU、延遲和正常運行時間成正比）</li><li><strong>國庫</strong>：用於網絡維護（例如 AI DA 費用、安全審計）和開發者資助</li><li><strong>治理池</strong>：激勵 $DGAI 持有者參與投票（例如協議升級、參數調整）。</li></ul><ol start="3"><li><strong>質押與鎖定要求</strong></li></ol><p>參與網絡的節點必須將 $DGAI 作為抵押品進行鎖定，以確保責任落實。</p><ol start="4"><li><strong>治理與費用分配</strong></li></ol><ul><li><strong>治理池</strong>：任務支付的5%（加上每年國庫資金的10%）將分配給參與提案投票的$DGAI持有者（例如調整基礎價格、白名單新模型等）。</li><li><strong>網絡費用</strong>：所有任務支付的 2% 處理費將提前扣除，用於覆蓋智能合約 gas 成本和 AI DA 存檔，確保交易效率。</li></ul><ol start="5"><li><strong>懲罰機製與代幣銷毀</strong></li></ol><p>節點違規行為將觸發自動懲罰以保護網絡完整性：</p><ul><li><p><strong>被沒收的代幣</strong>： 因惡意行為（如提交虛假推理結果、停機時間超過72小時）將沒收節點質押的$DGAI代幣的5–20%。</p></li><li><p><strong>銷毀機製</strong>：所有被罰沒的代幣將被永久銷毀，隨著時間推移減少$DGAI的總供應量並增強稀缺性。</p></li></ul><h2 id="關鍵流程-資金流入與流出" tabindex="-1">關鍵流程：資金流入與流出 <a class="header-anchor" href="#關鍵流程-資金流入與流出" aria-label="Permalink to &quot;關鍵流程：資金流入與流出&quot;">​</a></h2><table tabindex="0"><thead><tr><th>流入（$DGAI 的來源）</th><th>流出（$DGAI 的用途）</th></tr></thead><tbody><tr><td>用戶為推理任務支付的費用</td><td>節點運營商的推理任務報酬</td></tr><tr><td>DGrid節點周獎勵</td><td>節點參與的質押鎖定</td></tr><tr><td>投票參與者的治理獎勵</td><td>網絡費用（gas、AI DA 存檔）</td></tr><tr><td>初始分配（例如公開發售、空投）</td><td>被削減的代幣（銷毀）</td></tr></tbody></table><p>該機製確保$DGAI同時作為交換媒介和治理工具保持實用性，培育一個自我維持的生態系統，其中價值與網絡參與度成正比。通過將支付與貢獻掛鉤並通過質押機製強製執行問責製，$DGAI的流通量強化了DGrid AI的去中心化和韌性。</p>',24)]))}const u=l(a,[["render",s]]);export{h as __pageData,u as default};
